+    #[test]
+    fn test_morsel_insert_dispatch_64_rows() {
+        let conn = Connection::open(":memory:").unwrap();
+        conn.execute("CREATE TABLE t (id INTEGER PRIMARY KEY, v TEXT);")
+            .unwrap();
+        let mut sql = String::from("INSERT INTO t VALUES ");
+        for i in 0..64 {
+            if i > 0 {
+                sql.push_str(", ");
+            }
+            sql.push_str(&format!("({i}, 'row{i}')"));
+        }
+        sql.push(';');
+        conn.execute(&sql).unwrap();
+        let rows = conn.query("SELECT COUNT(*) FROM t;").unwrap();
+        assert_eq!(rows[0].values(), &[SqliteValue::Integer(64)]);
+        let rows = conn
+            .query("SELECT id, v FROM t ORDER BY id LIMIT 3;")
+            .unwrap();
+        assert_eq!(
+            rows.iter().map(row_values).collect::<Vec<_>>(),
+            vec![
+                vec![SqliteValue::Integer(0), SqliteValue::Text("row0".into())],
+                vec![SqliteValue::Integer(1), SqliteValue::Text("row1".into())],
+                vec![SqliteValue::Integer(2), SqliteValue::Text("row2".into())],
+            ]
+        );
+        let rows = conn.query("SELECT id, v FROM t WHERE id = 63;").unwrap();
+        assert_eq!(
+            rows[0].values(),
+            &[SqliteValue::Integer(63), SqliteValue::Text("row63".into()),]
+        );
+    }
+
+    #[test]
+    fn test_morsel_insert_dispatch_200_rows() {
+        let conn = Connection::open(":memory:").unwrap();
+        conn.execute("CREATE TABLE t (id INTEGER PRIMARY KEY, a INTEGER, b REAL, c TEXT);")
+            .unwrap();
+        let mut sql = String::from("INSERT INTO t VALUES ");
+        for i in 0..200 {
+            if i > 0 {
+                sql.push_str(", ");
+            }
+            sql.push_str(&format!("({i}, {}, {}.5, 'val{i}')", i * 10, i));
+        }
+        sql.push(';');
+        conn.execute(&sql).unwrap();
+        let rows = conn.query("SELECT COUNT(*) FROM t;").unwrap();
+        assert_eq!(rows[0].values(), &[SqliteValue::Integer(200)]);
+        let rows = conn.query("SELECT SUM(a), AVG(b) FROM t;").unwrap();
+        assert_eq!(rows[0].values()[0], SqliteValue::Integer(199_000));
+    }
